SELECT participants.participant_name
FROM participants
LEFT JOIN responses ON participants.participant_id = responses.participant_id;

SELECT gameid, COUNT(DISTINCT participant_id) AS total_participants
FROM experiments
GROUP BY gameid;

SELECT participants.participant_name, experiments.experiment_type
FROM participants
INNER JOIN experiments ON participants.participant_id = experiments.participant_id;

SELECT r.researcher_name, e.experiment_type
FROM researchers r
JOIN experiments e ON r.researcher_id = e.researcher_id;

SELECT AVG(confidence_level) 
FROM responses 
WHERE experiment_id = 1;

SELECT MIN(strftime('%s', t2.click_time) - strftime('%s', t1.response_time)) AS fastest_click_time
FROM responses AS t1
INNER JOIN click_data AS t2 ON t1.response_id = t2.response_id;
